          }

          broadcast(event, topic);
        } catch (err) {
          logger.error({ err }, "API Server failed to parse/broadcast event");
        }
      }
    });
  } catch (err) {
    logger.warn({ err }, "Redis state messaging bridge is offline. Real-time updates disabled.");
  }
}

