let consecutiveZeroGenerationCycles = 0;
let lastGenerationStartedAtMs = 0;
let totalGenerationDurationMs = 0;

function normalizeSymbol(symbol: string): string {
  const raw = symbol.trim().toUpperCase();
  if (!raw) return raw;
  return raw
    .replace(/^NSE[:_]/, "")
    .replace(/^NSE_EQ\|/, "")
    .replace(/-EQ$/, "")
    .replace(/\.NS$/, "");
}
export interface SuggestionGenerationDiagnostics {
  running: boolean;
  lastRunAt: string | null;
  lastSuccessAt: string | null;
  lastDurationMs: number | null;
  averageDurationMs: number | null;
  runCount: number;
  generated: number;
  eligibleCandidates: number;
  watchlistDateUsed: string | null;
  rejectionCounts: Record<string, number>;
  rejectionSummary?: Record<string, number>;
  note: string | null;
}

async function withTimeout<T>(
  task: Promise<T>,
  timeoutMs: number,
  label: string,
): Promise<T> {
  let timeoutId: ReturnType<typeof setTimeout> | undefined;
  const timeoutPromise = new Promise<never>((_, reject) => {
    timeoutId = setTimeout(() => {
      reject(new Error(`${label} timed out after ${timeoutMs}ms`));
    }, timeoutMs);
  });
  try {
    return await Promise.race([task, timeoutPromise]);
  } finally {
    if (timeoutId) clearTimeout(timeoutId);
  }
}

async function runInBatches<T, R>(
  items: T[],
  concurrency: number,
  worker: (item: T, index: number) => Promise<R>,
): Promise<R[]> {
  if (!items.length) return [];
  const results: R[] = new Array(items.length);
  let cursor = 0;
  const size = Math.max(1, concurrency);
  await Promise.all(
    Array.from({ length: Math.min(size, items.length) }, async () => {
      while (true) {
        const idx = cursor++;
        if (idx >= items.length) return;
        results[idx] = await worker(items[idx]!, idx);
      }
    }),
  );
  return results;
}

let lastGenerationDiagnostics: SuggestionGenerationDiagnostics = {
  running: false,
  lastRunAt: null,
  lastSuccessAt: null,
  lastDurationMs: null,
  averageDurationMs: null,
  runCount: 0,
  generated: 0,
  eligibleCandidates: 0,
  watchlistDateUsed: null,
  rejectionCounts: {},
  rejectionSummary: {},
  note: null,
};

export function getSuggestionGenerationDiagnostics(): SuggestionGenerationDiagnostics {
  return {
    ...lastGenerationDiagnostics,
    rejectionCounts: { ...lastGenerationDiagnostics.rejectionCounts },
    rejectionSummary: { ...(lastGenerationDiagnostics.rejectionSummary ?? {}) },
  };
}

function summarizeRejections(rejectionCounts: Record<string, number>): Record<string, number> {
  const summary: Record<string, number> = {
    data_unavailable: 0,
    setup_unavailable: 0,
    quality_gate: 0,
    risk_gate: 0,
    capacity_gate: 0,
    execution_guard: 0,
    system_error: 0,
  };

  const add = (key: keyof typeof summary, value: number) => {
    summary[key] = (summary[key] ?? 0) + value;
  };

  for (const [reason, count] of Object.entries(rejectionCounts)) {
    if (reason.startsWith("scan_null_insufficient") || reason === "symbol_not_found") {
      add("data_unavailable", count);
      continue;
    }
    if (reason.startsWith("scan_null_no_setup") || reason.startsWith("scan_null_quality_or_rs")) {
      add("setup_unavailable", count);
      continue;
    }
    if (["hourly_or_score", "min_suggestion_score", "mtf_conflict", "mtf_confluence", "confidence", "market_context"].includes(reason)) {
      add("quality_gate", count);
      continue;
    }
    if (["risk_reward", "position_sizing"].includes(reason)) {
      add("risk_gate", count);
      continue;
    }
    if (["sector_cap", "direction_cap_buy", "direction_cap_sell", "already_open"].includes(reason)) {
      add("capacity_gate", count);
      continue;
    }
    if (["signal_cooldown", "downtrend_vix_long_block", "uptrend_short_block"].includes(reason)) {
      add("execution_guard", count);
      continue;
    }
    if (["scan_timeout", "exception"].includes(reason)) {
      add("system_error", count);
      continue;
    }
  }

  return summary;
}


function getSessionMinuteIST(): number {
  const now = new Date();
  const utcMinutes = now.getUTCHours() * 60 + now.getUTCMinutes();
  const istMinutes = (utcMinutes + 330 + 24 * 60) % (24 * 60);
  return istMinutes - (9 * 60 + 15);
}

// ── Optimized LTP fetcher with batching and caching ────────────────────────

export async function fetchLTPForSymbols(
  symbols: string[],
): Promise<Record<string, number>> {
  if (symbols.length === 0) return {};

  const token = getAccessToken();
  if (!token) return {};

  // Map symbols to instrument keys
  const keyMap: Record<string, string> = {};
  const effectiveUniverse = await getEffectiveUniverse();
  for (const s of effectiveUniverse) keyMap[s.symbol] = s.key;

  const instrumentKeys = symbols
    .map((sym) => keyMap[sym])
    .filter((k): k is string => k != null);

  if (instrumentKeys.length === 0) return {};

  try {
    const data = await upstoxClient.fetchLTPForInstruments(
      instrumentKeys,
      token,
    );

    // Map back to symbols
    const result: Record<string, number> = {};
    for (const symbol of symbols) {
      const key = keyMap[symbol];
      if (key && data[key]) {
        result[symbol] = data[key];
      }
    }

    logger.info(
      { fetched: Object.keys(result).length, requested: symbols.length },
      "LTP fetch completed",
    );
    return result;
  } catch (err) {
    logger.error(
      { err, symbols: symbols.length },
      "Failed to fetch LTP for symbols",
    );
    return {};
  }
}

// ── Outcome check ─────────────────────────────────────────────────────────────

export async function runOutcomeCheck(): Promise<void> {
  try {
    const active = await db
      .select({ symbol: suggestionsTable.symbol })
      .from(suggestionsTable)
      .where(eq(suggestionsTable.status, "ACTIVE"));

    if (!active.length) return;

    const symbols = [...new Set(active.map((r) => r.symbol))];
    const prices = await fetchLTPForSymbols(symbols);
    if (Object.keys(prices).length === 0) return;

    await checkSuggestionOutcomes(prices);
  } catch (err) {
    logger.error({ err }, "runOutcomeCheck failed");
  }
}

// ── Sector concentration helper ───────────────────────────────────────────────

async function getOpenSectorCounts(): Promise<Record<string, number>> {
  const open = await db
    .select({ symbol: suggestionsTable.symbol })
    .from(suggestionsTable)
    .where(eq(suggestionsTable.status, "ACTIVE"));

  const counts: Record<string, number> = {};
  for (const row of open) {
    const sector = STOCK_SECTOR_MAP[row.symbol] ?? "Other";
    counts[sector] = (counts[sector] ?? 0) + 1;
  }
  return counts;
}

// ── Main suggestion generator ─────────────────────────────────────────────────

export async function generateSuggestionsFromWatchlist(options?: {
  bypassTimingFilter?: boolean;
  source?: "scheduler" | "manual" | "startup";
  scanSessionId?: string;
}): Promise<void> {
  const nowMs = Date.now();
  if (nowMs - lastGenerationStartedAtMs < MIN_GENERATION_GAP_MS) {
    logger.info(
      { minGapMs: MIN_GENERATION_GAP_MS },
      "Suggestion generation skipped due to minimum interval guard",
    );
    return;
  }

  if (generationInProgress) {
    logger.warn(
      "Suggestion generation skipped because previous generation is still running",
    );
    return;
  }

  const workflow = beginWorkflow(
    "INTRADAY_GENERATION",
    options?.source ?? "scheduler",
  );
  if (!workflow.ok) {
    logger.warn(
      { reason: workflow.reason },
      "Suggestion generation skipped due to workflow conflict",
    );
    lastGenerationDiagnostics.note = `Skipped: ${workflow.reason}`;
    return;
  }

  generationInProgress = true;
  lastGenerationStartedAtMs = nowMs;
  let workflowSuccess = true;
  let workflowFailureReason: string | undefined;
  lastGenerationDiagnostics = {
    ...lastGenerationDiagnostics,
    running: true,
    lastRunAt: new Date().toISOString(),
    lastDurationMs: null,
    generated: 0,
    eligibleCandidates: 0,
    rejectionCounts: {},
    note: "Generation cycle started.",
  };
  try {
    const cfg = getConfig();
    const state = getMarketState();

    if (state.suggestionsPaused) {
      logger.info(
        { reason: state.pauseReason },
        "Suggestion generation paused",
      );
      lastGenerationDiagnostics.note = `Paused: ${state.pauseReason ?? "unknown reason"}`;
      return;
    }

    if (!getAccessToken()) {
      logger.warn("Suggestion generation skipped — Upstox not authenticated");
      lastGenerationDiagnostics.note = "Skipped: Upstox not authenticated.";
      return;
    }

    const todayIST = getISTDateStr();
    const nextTradingDay = getNextTradingDayStr();

    const openSuggestions = await db
      .select()
      .from(suggestionsTable)
      .where(eq(suggestionsTable.status, "ACTIVE"));

    if (openSuggestions.length >= cfg.maxOpenPositions) {
      logger.info(
        { open: openSuggestions.length, max: cfg.maxOpenPositions },
        "Max open positions reached",
      );
      lastGenerationDiagnostics.note = "Skipped: max open positions reached.";
      return;
    }

    const slotsAvailable = cfg.maxOpenPositions - openSuggestions.length;
    const existingSymbols = new Set(openSuggestions.map((s) => normalizeSymbol(s.symbol)));

    const marketMinute = getSessionMinuteIST();
    if (
      !options?.bypassTimingFilter &&
      marketMinute >= 0 &&
      marketMinute < cfg.avoidFirstMinutes
    ) {
      logger.info({ marketMinute }, "Skipping generation due to execution timing filter");
      lastGenerationDiagnostics.note = "Skipped due to execution timing filter.";
      return;
    }

    // Fetch supporting data in parallel
    const [todayCandidates, nextDayCandidates, corporateBlacklist, sectorCounts, niftyCandles] =
      await Promise.all([
        db
          .select()
          .from(overnightWatchlistTable)
          .where(eq(overnightWatchlistTable.forDate, todayIST)),
        db
          .select()
          .from(overnightWatchlistTable)
          .where(eq(overnightWatchlistTable.forDate, nextTradingDay)),
        fetchCorporateActionBlacklist(),
        getOpenSectorCounts(),
        fetchNiftyDailyCandles(70),
      ]);
    
    let candidates = todayCandidates.length > 0 ? todayCandidates : nextDayCandidates;
    let watchlistDateUsed = todayCandidates.length > 0 ? todayIST : nextTradingDay;

    if (candidates.length === 0) {
      const [latest] = await db
        .select({ forDate: overnightWatchlistTable.forDate })
        .from(overnightWatchlistTable)
        .orderBy(desc(overnightWatchlistTable.forDate))
        .limit(1);
      if (latest?.forDate) {
        candidates = await db
          .select()
          .from(overnightWatchlistTable)
          .where(eq(overnightWatchlistTable.forDate, latest.forDate));
        watchlistDateUsed = latest.forDate;
        logger.info(
          { count: candidates.length, latestDate: latest.forDate },
          "Watchlist empty for today/tomorrow; falling back to latest available watchlist",
        );
      }
    }

    logger.info(
      {
        watchlistCount: candidates.length,
        watchlistDateUsed,
        existingOpen: openSuggestions.length,
        slotsAvailable,
      },
      "Generation cycle started",
    );

    const regime = state.regime;
    if (regime === "TRENDING_DOWN" && state.indiaVix && state.indiaVix > 18) {
      logger.info("Skipping long generation — downtrend with elevated VIX");
    }

    const normalizedCandidates = candidates.map((c) => ({
      ...c,
      symbol: normalizeSymbol(c.symbol),
    }));

    const eligibleCandidates = normalizedCandidates
      .filter((c) => {
        if (c.category === "AVOID") return false;
        if (existingSymbols.has(c.symbol)) return false;
        if (corporateBlacklist.has(c.symbol)) {
          logger.debug(
            { symbol: c.symbol },
            "Skipping — corporate action in next 3 days",
          );
          return false;
        }
        return true;
      })
      .sort((a, b) => (b.priority ?? 0) - (a.priority ?? 0))
      .slice(0, slotsAvailable * CANDIDATE_OVERSAMPLE_FACTOR);

    if (!eligibleCandidates.length) {
      logger.warn(
        { watchlistSize: candidates.length, reason: "empty or all filtered" },
        "No eligible candidates available for generation",
      );
      lastGenerationDiagnostics = {
        ...lastGenerationDiagnostics,
        running: false,
        generated: 0,
        eligibleCandidates: 0,
        watchlistDateUsed: watchlistDateUsed,
        rejectionCounts: {},
        note: "No eligible candidates after pre-filters.",
      };
      
      broadcast(
        createServerEvent.scanCompleted({
          suggestionsGenerated: 0,
          duration: Date.now() - nowMs,
          scanSessionId: options?.scanSessionId,
        }),
      );
      
      return;
    }

    logger.info(
      { candidates: eligibleCandidates.length, slots: slotsAvailable },
      "Generating suggestions",
    );
    broadcast(
      createServerEvent.scanStarted({
        stocksToAnalyze: eligibleCandidates.length,
        timestamp: new Date().toISOString(),
        scanSessionId: options?.scanSessionId,
      }),
    );

    let generated = 0;
    const rejectionCounts: Record<string, number> = {};
    const addRejection = (reason: string) => {
      rejectionCounts[reason] = (rejectionCounts[reason] ?? 0) + 1;
    };


    let completedCount = 0;
    const analyzed = await runInBatches(
      eligibleCandidates,
      SCAN_CONCURRENCY,
      async (candidate) => {
        broadcast(
          createServerEvent.scanProgress({
            current: completedCount,
            total: eligibleCandidates.length,
            currentStock: candidate.symbol,
            status: "ANALYZING",
            scanSessionId: options?.scanSessionId,
          }),
        );
        const stock = await findStockBySymbol(candidate.symbol);
        if (!stock) {
          completedCount++;
          broadcast(
            createServerEvent.scanProgress({
              current: completedCount,
              total: eligibleCandidates.length,
              currentStock: candidate.symbol,
              status: "FAILED",
              reason: "symbol_not_found",
              scanSessionId: options?.scanSessionId,
            }),
          );
          return { candidate, stock: null, result: null, scanNullReason: "symbol_not_found" };
        }
        try {
          const result = await withTimeout(
            scanStock(stock, niftyCandles),
            PER_CANDIDATE_TIMEOUT_MS,
            `scanStock(${stock.symbol})`,
          );
          if (!result) {
            const reason = await diagnoseScanNullReason(stock);
            completedCount++;
            broadcast(
              createServerEvent.scanProgress({
                current: completedCount,
                total: eligibleCandidates.length,
                currentStock: candidate.symbol,
                status: "FAILED",
                reason,
                scanSessionId: options?.scanSessionId,
              }),
            );
            return { candidate, stock, result: null, scanNullReason: reason };
          }
          completedCount++;
          broadcast(
            createServerEvent.scanProgress({
              current: completedCount,
              total: eligibleCandidates.length,
              currentStock: candidate.symbol,
              status: "PASSED",
              scanSessionId: options?.scanSessionId,
            }),
          );
          return { candidate, stock, result, scanNullReason: null };
        } catch (err) {
          logger.error({ err, symbol: candidate.symbol }, "Error scanning candidate");
          completedCount++;
          broadcast(
            createServerEvent.scanProgress({
              current: completedCount,
              total: eligibleCandidates.length,
              currentStock: candidate.symbol,
              status: "FAILED",
              reason: "exception",
              scanSessionId: options?.scanSessionId,
            }),
          );
          return { candidate, stock, result: null, scanNullReason: "exception" };
        }
      },
    );

    const scanResults: ScanResult[] = analyzed
      .map((item) => item.result)
      .filter((r): r is ScanResult => r !== null);

    // Track rejections
    for (const item of analyzed) {
      if (!item.result && item.scanNullReason) {
        addRejection(item.scanNullReason);
      }
    }

    logger.info({ scanResults: scanResults.length }, "Running consolidated scan results through Layer 7 pipeline");
    const pipelineResult = await runIntelligencePipeline(scanResults);

    // Calculate dynamic minimum RR threshold based on India VIX and Market Breadth
    let minRequiredRR = 1.3;
    if (state.indiaVix && state.indiaVix > 16) {
      minRequiredRR += 0.2;
    }
    if (state.declineCount > 0 && state.advanceCount > 0 && state.declineCount > state.advanceCount * 1.5) {
      minRequiredRR += 0.25;
    }

    // Fetch live market prices (LTP) so we never suggest outdated/chased entry prices from daily historical candles
    const candidateSymbols = pipelineResult.signals.map((s) => s.symbol);
    const livePrices = candidateSymbols.length ? await fetchLTPForSymbols(candidateSymbols).catch(() => ({} as Record<string, number>)) : {};

    for (const signal of pipelineResult.signals) {
      if (generated >= slotsAvailable) break;

      const ltp = livePrices[signal.symbol];
      const candidate = eligibleCandidates.find(c => c.symbol === signal.symbol);
      const isIntraday = candidate?.category?.toUpperCase().includes("INTRADAY") ?? false;
      
      const success = await ingestSignal(signal, ltp, {
        scanSessionId: options?.scanSessionId,
        source: options?.source,
        isIntraday,
        minRequiredRR
      });

      if (success) {
        generated++;
        const sector = STOCK_SECTOR_MAP[signal.symbol] ?? "Other";
        sectorCounts[sector] = (sectorCounts[sector] ?? 0) + 1;
      }
    }

    const rejectionSummary = summarizeRejections(rejectionCounts);
    const durationMs = Date.now() - nowMs;
    totalGenerationDurationMs += durationMs;
    const completedRunCount = lastGenerationDiagnostics.runCount + 1;
    lastGenerationDiagnostics = {
      running: false,
      lastRunAt: new Date().toISOString(),
      lastDurationMs: durationMs,
      averageDurationMs: totalGenerationDurationMs / completedRunCount,
      runCount: completedRunCount,
      lastSuccessAt: generated > 0 ? new Date().toISOString() : lastGenerationDiagnostics.lastSuccessAt,
      generated,
      eligibleCandidates: eligibleCandidates.length,
      watchlistDateUsed: watchlistDateUsed,
      rejectionCounts,
      rejectionSummary,
      note:
        generated > 0
          ? "Quality-filtered suggestions generated."
          : (consecutiveZeroGenerationCycles >= 2)
            ? "No suggestion met adaptive quality gates in this cycle."
            : "No suggestion met strict quality gates in this cycle.",
    };
    consecutiveZeroGenerationCycles = generated > 0 ? 0 : consecutiveZeroGenerationCycles + 1;

    logger.info(
      { generated, total: eligibleCandidates.length, rejectionCounts },
      "Suggestion generation complete",
    );
    broadcast(
      createServerEvent.scanCompleted({
        suggestionsGenerated: generated,
        duration: durationMs,
        scanSessionId: options?.scanSessionId,
      }),
    );
  } catch (err) {
    workflowSuccess = false;
    workflowFailureReason =
      err instanceof Error ? err.message : "unknown generation error";
    const durationMs = Date.now() - nowMs;
    broadcast(
      createServerEvent.scanCompleted({
        suggestionsGenerated: 0,
        duration: durationMs,
        scanSessionId: options?.scanSessionId,
      }),
    );
    throw err;
  } finally {
    lastGenerationDiagnostics.running = false;
    generationInProgress = false;
    endWorkflow("INTRADAY_GENERATION", workflowSuccess, workflowFailureReason);
  }
}


export async function ingestSignal(
  signal: IntelligenceSignal,
  livePrice?: number,
  options?: {
    scanSessionId?: string;
    source?: string;
    isIntraday?: boolean;
    minRequiredRR?: number;
  }
): Promise<boolean> {
  const ltp = livePrice;
  const minRequiredRR = options?.minRequiredRR ?? 1.3;

  if (ltp && ltp > 0) {
    if (signal.signal === "BUY") {
      if (ltp > signal.entryPrice * 1.002) {
        logger.warn({ symbol: signal.symbol, ltp, origEntry: signal.entryPrice }, "Discarding BUY suggestion: live price has already passed planned entry point (Late Entry / Chased)");
        return false;
      }
      const liveRisk = ltp - signal.stopLoss;
      const liveReward = signal.target1 - ltp;
      const liveRR = liveRisk > 0 ? liveReward / liveRisk : 0;
      if (ltp <= signal.stopLoss || ltp >= signal.target1 || liveRR < minRequiredRR) {
        logger.warn({ symbol: signal.symbol, ltp, origEntry: signal.entryPrice, liveRR, minRequiredRR }, "Discarding suggestion: live price has hit target/stop or risk-reward < minRequiredRR");
        return false;
      }
      signal.riskReward = Number(liveRR.toFixed(2));
    } else if (signal.signal === "SELL") {
      if (ltp < signal.entryPrice * 0.998) {
        logger.warn({ symbol: signal.symbol, ltp, origEntry: signal.entryPrice }, "Discarding SELL suggestion: live price has already passed planned entry point (Late Entry / Chased)");
        return false;
      }
      const liveRisk = signal.stopLoss - ltp;
      const liveReward = ltp - signal.target1;
      const liveRR = liveRisk > 0 ? liveReward / liveRisk : 0;
      if (ltp >= signal.stopLoss || ltp <= signal.target1 || liveRR < minRequiredRR) {
        logger.warn({ symbol: signal.symbol, ltp, origEntry: signal.entryPrice, liveRR, minRequiredRR }, "Discarding suggestion: live price has hit target/stop or risk-reward < minRequiredRR");
        return false;
      }
      signal.riskReward = Number(liveRR.toFixed(2));
    }
  }

  const todayStart = todayStartUTC();
  
  const [latestOpen] = await db
    .select({ id: suggestionsTable.id })
    .from(suggestionsTable)
    .where(
      and(
        eq(suggestionsTable.symbol, signal.symbol),
        or(
          gte(suggestionsTable.generatedAt, todayStart),
          eq(suggestionsTable.status, "ACTIVE")
        )
      )
    )
    .limit(1);

  if (latestOpen) return false;

  const isIntraday = options?.isIntraday ?? false;
  const tradeType = isIntraday ? "INTRADAY" : "SWING";
  
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const validityTill = isIntraday ? tomorrow.toISOString().slice(0, 10) : "3d";

  const [inserted] = await db
    .insert(suggestionsTable)
    .values({
      symbol: signal.symbol,
      name: signal.name,
      exchange: "NSE",
      direction: signal.signal,
      tradeType,
      setupType: signal.setupType,
      entryPrice: signal.entryPrice.toString(),
      stopLoss: signal.stopLoss.toString(),
      target1: signal.target1.toString(),
      target2: signal.target2 ? signal.target2.toString() : null,
      riskReward: signal.riskReward.toString(),
      quantity: signal.positionSize,
      maxRiskInr: signal.maxRiskInr.toString(),
      stopDistancePct: signal.stopDistancePct.toString(),
      marketRegime: signal.regime,
      confidence: signal.confidence,
      aiScore: signal.aiScore,
      patternScore: signal.patternScore,
      chronosScore: signal.chronosScore,
      technicalScore: signal.technicalScore,
      sentimentScore: signal.sentimentScore,
      rankingMode: signal.rankingProvider,
      reasoning: `[SENTIMENT: ${signal.sentimentScore > 60 ? "BULLISH" : signal.sentimentScore < 40 ? "BEARISH" : "NEUTRAL"}] ${signal.reasoning} Confluence: ${signal.confluence.slice(0, 2).join(", ")}.`,
      validityTill,
      status: "ACTIVE",
      atr: signal.featureVector?.atr14?.toString() || "0",
      highestPrice: signal.entryPrice.toString(),
      lowestPrice: signal.entryPrice.toString(),
      signalFactors: signal.signalFactors,
    })
    .returning();

  if (inserted) {
    logger.info({
      id: inserted.id,
      symbol: inserted.symbol,
      setupType: inserted.setupType,
      direction: inserted.direction,
      entryPrice: inserted.entryPrice
    }, "Database write: auto suggestion generated and inserted");

    broadcast(
      createServerEvent.newSuggestion({
        id: inserted.id,
        symbol: inserted.symbol,
        direction: signal.signal as "BUY" | "SELL",
        entryPrice: signal.entryPrice,
        stopLoss: signal.stopLoss,
        target1: signal.target1,
        setupType: signal.setupType,
        riskReward: signal.riskReward,
        scanSessionId: options?.scanSessionId,
      }),
      "suggestions"
    );

    intelligenceBus.publish("suggestionGenerated", {
      suggestion: {
        id: inserted.id,
        instrumentKey: `NSE_EQ|${inserted.symbol}`,
        symbol: inserted.symbol,
        direction: signal.signal as "BUY" | "SELL",
        setup: signal.setupType,
        confidence: signal.confidence,
        entry: signal.entryPrice,
        stopLoss: signal.stopLoss,
        target: signal.target1,
        target1: signal.target1,
        riskReward: signal.riskReward,
        reasoning: [signal.reasoning],
        generatedAt: Date.now(),
        expiresAt: Date.now() + 20 * 60_000,
      } as any
    });

    logger.info(
      {
        symbol: signal.symbol,
        setup: signal.setupType,
        direction: signal.signal,
        rr: signal.riskReward,
        confidence: signal.confidence,
      },
      "New suggestion generated via Layer 7 Pipeline"
    );
    return true;
  }
  return false;
}

import "../load-env.cjs";
import { config as dotenvConfig } from "dotenv";
import { logger } from "./lib/logger";
import { startScheduler } from "./scheduler/jobs";
import { initConfigFromDb } from "./config";
import { initAccessTokenFromDb } from "./upstox/auth";
import { startMarketIntelligence } from "./intelligence/orchestrator";
import { initPositionTracker } from "./trading/position_tracker";
import { createRedisClient } from "./lib/redis";
import path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));

// Global process-level crash guards
process.on("unhandledRejection", (reason: any, promise) => {
  logger.error({ promise, reason: reason instanceof Error ? reason.stack : reason }, "TRADING ENGINE CRITICAL: Unhandled Promise Rejection detected");
});

process.on("uncaughtException", (err) => {
  logger.fatal({ err }, "TRADING ENGINE CRITICAL: Uncaught Exception detected");
  process.exit(1);
});

dotenvConfig({ path: path.resolve(__dirname, "../.env.local"), override: true });
dotenvConfig({ path: path.resolve(__dirname, "../.env") });

const redisPub = createRedisClient("trading_engine_pub");

redisPub.on("error", (err) => {
  logger.debug({ err }, "Trading Engine Redis publisher error");
});

// Override the broadcast function in the WebSocket server module
// so that all events are published to Redis channel instead of local memory sockets
import { setBroadcastFn } from "./ws/websocket_server";
setBroadcastFn((event: unknown, topic: string = "suggestions") => {
  redisPub.publish("trading:events", JSON.stringify({ event, topic })).catch((err) => {
    logger.debug({ err }, "Trading Engine failed to publish event to Redis");
  });
});

async function main() {
  try {
    await redisPub.connect();
    logger.info("Trading Engine connected to Redis publisher");
  } catch (err) {
    logger.warn({ err }, "Redis state publisher is offline. Process bridging disabled.");
  }

  try {
    await initConfigFromDb();
    await initAccessTokenFromDb();
  } catch (err) {
    logger.warn({ err }, "Trading Engine: Startup state restore failed; continuing with defaults");
  }

  startScheduler();

  startMarketIntelligence().catch((err) => {
    logger.warn({ err }, "Market intelligence startup failed; legacy services continue");
  });

  initPositionTracker().catch((err) => {
    logger.error({ err }, "Trading Engine: Failed to initialize position tracker");
  });

  import("./trading/paper_engine").then(({ initPaperEngine }) => {
    initPaperEngine().catch((err) => {
      logger.error({ err }, "Trading Engine: Failed to initialize paper engine");
    });
  });

  logger.info("Trading Engine process started successfully.");
}

void main();

import crypto from "crypto";
import { WebSocketServer, WebSocket } from "ws";
import type { Server } from "http";
import { logger } from "../lib/logger";
import { parseClientEvent, ServerEvent, createServerEvent, packr } from "./events";
import { isAllowedOrigin } from "../lib/security";
import { createRedisClient } from "../lib/redis";

const redisSubscriber = createRedisClient("ws-subscriber");
redisSubscriber.connect().then(() => {
  return redisSubscriber.subscribe("mimir:alerts:pubsub");
}).catch(err => logger.error({ err }, "Failed to subscribe to alerts"));
redisSubscriber.on("message", (channel: string, message: string) => {
  if (channel === "mimir:alerts:pubsub") {
    try {
      const alertPayload = JSON.parse(message);
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      broadcast({ event: "alert", data: alertPayload } as any, "alerts");
    } catch (err) {
      logger.error({ err }, "Failed to parse alert from Redis");
    }
  }
});

const wssInstances: WebSocketServer[] = [];
let connectedCount = 0;
let lastTickLog = 0;

export function initWebSocketServer(server: Server): void {
  const wssIntelligence = new WebSocketServer({ noServer: true });
  const wssMarketData = new WebSocketServer({ noServer: true });

  wssInstances.push(wssIntelligence, wssMarketData);

  server.on("upgrade", (request, socket, head) => {
    const origin = request.headers.origin;
    
    if (origin && !isAllowedOrigin(origin)) {
      logger.error({ origin, isAllowed: isAllowedOrigin(origin), nodeEnv: process.env.NODE_ENV, headers: request.headers }, "401 Unauthorized in UPGRADE");
      socket.write("HTTP/1.1 401 Unauthorized\r\n\r\n");
      socket.destroy();
      return;
    }

    const pathname = request.url ? request.url.split("?")[0] : "";
    if (pathname === "/ws/intelligence") {
      wssIntelligence.handleUpgrade(request, socket, head, (ws) => {
        wssIntelligence.emit("connection", ws, request);
      });
    } else if (pathname === "/ws/market-data") {
      wssMarketData.handleUpgrade(request, socket, head, (ws) => {
        wssMarketData.emit("connection", ws, request);
      });
    } else {
      socket.destroy();
    }
  });

  const setupWs = (wss: WebSocketServer, name: string) => {
    wss.on("connection", (ws, request) => {
      connectedCount++;
      logger.info({ connectedClients: connectedCount, channel: name }, "WebSocket client connected");

      // Mark alive for heartbeat tracking and initialize default topics and symbol subscription
      const tc = ws as WebSocket & { isAlive: boolean; topics: Set<string>; activeSymbol: string | null; subscribedSymbols: Set<string>; channelName: string; isAuthenticated: boolean };
      tc.isAlive = true;
      tc.topics = new Set(["suggestions", "alerts"]); // default low-frequency subscription
      tc.activeSymbol = null; // no symbol subscription until client specifies
      tc.subscribedSymbols = new Set<string>();
      tc.channelName = name;
      tc.isAuthenticated = false;

      const ipStr = request?.socket?.remoteAddress;
      const normalizedIp = (ipStr || "").replace(/^::ffff:/, "");
      const isLocal = normalizedIp === "::1" || normalizedIp === "127.0.0.1" || normalizedIp.startsWith("127.");
      const isRemoteAuthDisabled = process.env.DISABLE_REMOTE_API_AUTH === "1" || process.env.DISABLE_REMOTE_API_AUTH === "true";

      if (isLocal || isRemoteAuthDisabled) {
        tc.isAuthenticated = true;
      } else {
        // Enforce 5-second auth timeout
        setTimeout(() => {
          if (!tc.isAuthenticated) {
            logger.warn({ channel: tc.channelName }, "Closing WS connection: Auth timeout");
            ws.close(4001, "Authentication timeout");
          }
        }, 5000);
      }

      ws.on("pong", () => {
        tc.isAlive = true;
      });

      ws.on("message", (raw) => {
        try {
          tc.isAlive = true; // Any message from client means it's alive
          
          let clientEvent;
          if (Buffer.isBuffer(raw) && raw[0] === 123) { 
            // 123 is '{', fallback for JSON strings sent as buffers
            clientEvent = parseClientEvent(raw.toString());
          } else if (typeof raw === "string") {
            clientEvent = parseClientEvent(raw);
          } else {
            // Binary MsgPack payload
            clientEvent = parseClientEvent(raw as Buffer);
          }

          if (!clientEvent) {
            logger.warn("Received invalid client event");
            return;
          }

          logger.info({ 
            event: clientEvent.event, 
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            topic: (clientEvent.data as any)?.topic, 
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            symbol: (clientEvent.data as any)?.symbol,
            channel: tc.channelName
          }, "Inbound WebSocket message");

          // Handle client events
          if (clientEvent.event === "auth") {
            const token = clientEvent.data?.token;
            const expectedToken = process.env.UPSTOXBOT_ADMIN_TOKEN?.trim();
            if (!expectedToken) {
              ws.close(4003, "Remote access disabled");
              return;
            }
            if (!token) {
              ws.close(4001, "Token required");
              return;
            }
            try {
              const left = Buffer.from(token);
              const right = Buffer.from(expectedToken);
              if (left.length !== right.length || !crypto.timingSafeEqual(left, right)) {
                throw new Error("Invalid token");
              }
              tc.isAuthenticated = true;
              logger.info({ channel: tc.channelName }, "WS client authenticated successfully");
            } catch {
              ws.close(4001, "Invalid token");
            }
            return;
          }

          if (!tc.isAuthenticated && clientEvent.event !== "ping") {
            logger.warn({ event: clientEvent.event }, "Ignoring event from unauthenticated client");
            return;
          }

          if (clientEvent.event === "ping") {
            ws.send(packr.pack(createServerEvent.pong()));
          } else if (clientEvent.event === "subscribe") {
            const topic = clientEvent.data.topic;
            tc.topics.add(topic);
            logger.debug({ topic, channel: tc.channelName }, "Client subscribed to topic");
          } else if (clientEvent.event === "unsubscribe") {
            const topic = clientEvent.data.topic;
            tc.topics.delete(topic);
            logger.debug({ topic, channel: tc.channelName }, "Client unsubscribed from topic");
          } else if (clientEvent.event === "subscribe_symbol") {
            const symbol = clientEvent.data.symbol;
            const oldSymbol = tc.activeSymbol;
            tc.activeSymbol = symbol;
            logger.debug({ symbol, channel: tc.channelName }, "Client subscribed to symbol");
            // Also automatically subscribe to "ticks" topic when symbol is specified
            tc.topics.add("ticks");

            if (symbol) {
              import("../market_data/monitored_symbols").then(({ addManualMonitoredSymbol }) => {
                void addManualMonitoredSymbol(symbol).catch(() => {});
              }).catch(() => {});
            }

            if (oldSymbol && oldSymbol !== symbol) {
              // Clean up old activeSymbol monitoring if no other client is currently subscribing to it
              const allClients = wssInstances.reduce((acc, w) => acc.concat(Array.from(w.clients)), [] as any[]);
              const otherSubscribed = allClients.some((client) => {
                const tcClient = client as WebSocket & { activeSymbol?: string | null };
                return tcClient !== ws && tcClient.activeSymbol === oldSymbol;
              });

              if (!otherSubscribed) {
                import("../market_data/monitored_symbols").then(({ removeManualMonitoredSymbol }) => {
                  void removeManualMonitoredSymbol(oldSymbol).catch(() => {});
                }).catch(() => {});
              }
            }
          } else if (clientEvent.event === "subscribe_symbols" || clientEvent.event === "subscribe_watchlist") {
            const symbols = Array.isArray(clientEvent.data.symbols) ? clientEvent.data.symbols : [];
            symbols.forEach((sym: string) => {
              if (sym && typeof sym === "string") tc.subscribedSymbols.add(sym.trim());
            });
            tc.topics.add("ticks");
            logger.debug({ count: symbols.length, channel: tc.channelName }, "Client subscribed to symbol batch/watchlist");

            if (symbols.length > 0) {
              import("../market_data/monitored_symbols").then(({ addManualMonitoredSymbols }) => {
                void addManualMonitoredSymbols(symbols).catch(() => {});
              }).catch(() => {});
            }
          }
        } catch (err) {
          logger.error({ err }, "Error handling WebSocket message");
        }
      });

      ws.on("close", () => {
        connectedCount--;
        logger.info({ connectedClients: connectedCount, channel: tc.channelName }, "WebSocket client disconnected");
        
        const oldSymbol = tc.activeSymbol;
        if (oldSymbol) {
          // Clean up old activeSymbol monitoring if no other client is currently subscribing to it
          const allClients = wssInstances.reduce((acc, w) => acc.concat(Array.from(w.clients)), [] as any[]);
          const otherSubscribed = allClients.some((client) => {
            const tcClient = client as WebSocket & { activeSymbol?: string | null };
            return tcClient !== ws && tcClient.activeSymbol === oldSymbol;
          });

          if (!otherSubscribed) {
            import("../market_data/monitored_symbols").then(({ removeManualMonitoredSymbol }) => {
              void removeManualMonitoredSymbol(oldSymbol).catch(() => {});
            }).catch(() => {});
          }
        }
      });

      ws.on("error", (err) => {
        logger.error({ err, channel: tc.channelName }, "WebSocket client error");
      });

      // Send initial connection confirmation (silent — UI shows Live/Offline in top bar)
      broadcastToClient(ws, createServerEvent.pong());
    });
  };

  setupWs(wssIntelligence, "intelligence");
  setupWs(wssMarketData, "market-data");

  // Server-side heartbeat: terminate dead connections every 30s
  setInterval(() => {
    wssInstances.forEach((wss) => {
      wss.clients.forEach((ws) => {
        const alive = ws as WebSocket & { isAlive: boolean };
        if (alive.isAlive === false) {
          logger.warn("Terminating unresponsive WebSocket client");
          ws.terminate();
          return;
        }
        alive.isAlive = false;
        ws.ping();
      });
    });
  }, 30000);

  logger.info("WebSocket servers initialized at /ws/intelligence and /ws/market-data");
}

/**
 * Send a typed event to a single client
 */
export function broadcastToClient(ws: WebSocket, event: ServerEvent): void {
  if (ws.readyState === WebSocket.OPEN) {
    ws.send(packr.pack(event));
  }
}

/**
 * Broadcast a typed event to all connected clients
 */
let broadcastFn = (event: ServerEvent, topic: string = "suggestions"): void => {
  const isTickEvent = event.event === "tick_update" || topic === "ticks";
  const execute = () => {
    let successCount = 0;
    
    wssInstances.forEach((wss) => {
      wss.clients.forEach((client) => {
        const tc = client as WebSocket & { topics?: Set<string>; activeSymbol?: string | null; channelName?: string; subscribedSymbols?: Set<string> };
        if (tc.readyState === WebSocket.OPEN) {
          // Enforce channel routing
          if (isTickEvent && tc.channelName === "intelligence") return;
          if (!isTickEvent && tc.channelName === "market-data" && topic !== "monitoring") return;

          if (topic === "all" || !tc.topics || tc.topics.has(topic)) {
            // Extra filtering: if this is a tick update, filter by activeSymbol + subscribedSymbols + indices
            if (isTickEvent && Array.isArray(event.data)) {
              if (event.data.length === 0) return;
              client.send(packr.pack(event));
              successCount++;
              return;
            }

            client.send(packr.pack(event));
            successCount++;
          }
        }
      });
    });

    if (successCount > 0) {
      logger.info({ 
        event: event.event, 
        topic,
        clients: successCount 
      }, "Outbound WebSocket broadcast");
    }
  };

  if (isTickEvent) {
    execute();
  } else {
    setImmediate(execute);
  }
};

export function broadcast(event: ServerEvent, topic: string = "system") {
  if (topic !== "ticks") {
    logger.info({ event: event.event, topic, clients: connectedCount }, "Outbound WebSocket broadcast");
  } else {
    if (Date.now() - lastTickLog > 5000) {
      lastTickLog = Date.now();
      logger.info({ event: event.event, topic, clients: connectedCount }, "Outbound WebSocket broadcast (ticks throttle)");
    }
  }
  broadcastFn(event, topic);
}

export function setBroadcastFn(fn: typeof broadcastFn): void {
  broadcastFn = fn;
}

/**
 * Get the number of connected clients
 */
export function getConnectedClients(): number {
  let count = 0;
  for (const instance of wssInstances) {
    for (const client of instance.clients) {
      if (client.readyState === WebSocket.OPEN) count++;
    }
  }
  return count;
}

/**
 * Export types for consumers
 */
export type { ServerEvent } from "./events";

/**
 * High-performance batched tick broadcaster
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function broadcastMarketTicks(ticks: any[]): void {
  if (!ticks || ticks.length === 0) return;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  broadcast({ event: "tick_update", data: ticks } as any, "ticks");
}

import { describe, it, expect, vi, beforeEach } from "vitest";
import { computeFiiDiiDivergence } from "../src/analysis/divergence_engine";
import yahooFinance from "yahoo-finance2";
import { db } from "../../db/src";

vi.mock("yahoo-finance2", () => {
  return {
    default: {
      historical: vi.fn()
    }
  };
});

vi.mock("../db/src", () => {
  const limitMock = vi.fn();
  const orderByMock = vi.fn().mockReturnValue({ limit: limitMock });
  const fromMock = vi.fn().mockReturnValue({ orderBy: orderByMock });
  const selectMock = vi.fn().mockReturnValue({ from: fromMock });

  return {
    db: {
      select: selectMock
    }
  };
});

// Since the module is mocked, we can just grab the limitMock from db.select().from().orderBy().limit
const getLimitMock = () => {
  return (db.select().from({} as any).orderBy({} as any) as any).limit;
};

describe("Divergence Engine", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("should flag bullish divergence when Nifty falls but FII/DII buys heavily", async () => {
    // 5-day flow: 2500 Cr (Bullish)
    const limitMock = getLimitMock();
    limitMock.mockResolvedValue([
      { fiiNet: 500, diiNet: 500 },
      { fiiNet: 500, diiNet: -250 },
      { fiiNet: 200, diiNet: 200 },
      { fiiNet: 800, diiNet: 0 },
      { fiiNet: 50, diiNet: 0 }
    ]); // Total = 500+500+500-250+200+200+800+0+50+0 = 2500 Cr

    // Nifty returns: falls by 2%
    (yahooFinance.historical as any).mockResolvedValue([
      { close: 20000 },
      { close: 19900 },
      { close: 19800 },
      { close: 19700 },
      { close: 19600 } // 19600/20000 - 1 = -2%
    ]);

    const result = await computeFiiDiiDivergence();

    expect(result.totalFlow5d).toBe(2500);
    expect(result.niftyReturn5d).toBeCloseTo(-2.0);
    expect(result.isDiverging).toBe(true);
    expect(result.divergenceType).toBe("BULLISH");
    expect(result.penaltyOrBoost).toBe(10);
  });

  it("should flag bearish divergence when Nifty rallies but FII/DII sells heavily", async () => {
    // 5-day flow: -2500 Cr (Bearish)
    const limitMock = getLimitMock();
    limitMock.mockResolvedValue([
      { fiiNet: -1000, diiNet: -500 },
      { fiiNet: -500, diiNet: 0 },
      { fiiNet: -500, diiNet: 0 },
      { fiiNet: 0, diiNet: 0 },
      { fiiNet: 0, diiNet: 0 }
    ]);

    // Nifty returns: rallies by 2%
    (yahooFinance.historical as any).mockResolvedValue([
      { close: 20000 },
      { close: 20100 },
      { close: 20200 },
      { close: 20300 },
      { close: 20400 } // 20400/20000 - 1 = +2%
    ]);

    const result = await computeFiiDiiDivergence();

    expect(result.totalFlow5d).toBe(-2500);
    expect(result.niftyReturn5d).toBeCloseTo(2.0);
    expect(result.isDiverging).toBe(true);
    expect(result.divergenceType).toBe("BEARISH");
    expect(result.penaltyOrBoost).toBe(-10);
  });
});

